import itertools
import math
from causallearn.utils.DAG2CPDAG import dag2cpdag
from causallearn.graph.Edge import Edge
from causallearn.graph.Endpoint import Endpoint
from causallearn.utils.PCUtils import SkeletonDiscovery
from causallearn.utils.cit import CIT

def run_causal_discovery(X: np.ndarray) -> GeneralGraph:
    n, d = X.shape
    nodes = [GraphNode(f"X{i + 1}") for i in range(d)]
    C = np.cov(X.T, bias=True)

    indep_test = CIT(X, "fisherz")
    try:
        cg = SkeletonDiscovery.skeleton_discovery(X, 0.1, indep_test)
        skel = cg.G.graph
    except:
        skel = np.ones((d, d))

    C_corr = np.corrcoef(X.T)
    cand = []
    for i in range(d):
        c_i = set()
        for j in range(d):
            if skel[i, j] != 0: c_i.add(j)
        top_j = np.argsort(-np.abs(C_corr[i]))
        added = 0
        for j in top_j:
            if j == i: continue
            if added >= 5: break
            c_i.add(j)
            added += 1
        cand.append(tuple(sorted(list(c_i))))

    parent_cache = {}

    def calc_ebic(target, S):
        sz = len(S)
        if sz == 0:
            var_res = C[target, target]
            if var_res <= 0: var_res = 1e-8
            return n * np.log(var_res)

        Css = C[np.ix_(S, S)] + np.eye(sz) * 1e-6
        Csy = C[S, target]
        try:
            beta = np.linalg.solve(Css, Csy)
        except:
            beta = np.linalg.lstsq(Css, Csy, rcond=None)[0]
        var_res = C[target, target] - np.dot(C[target, S], beta)
        if var_res <= 0: var_res = 1e-8

        gamma = 0.5
        bic_pen = sz * np.log(n)
        if gamma > 0:
            bic_pen += 2 * gamma * np.log(math.comb(d, sz))
        return n * np.log(var_res) + bic_pen

    def get_best_parents(target, avail_candidates):
        if len(avail_candidates) == 0:
            sc = calc_ebic(target, [])
            parent_cache[(target, avail_candidates)] = ((), sc)
            return (), sc
        if (target, avail_candidates) in parent_cache:
            return parent_cache[(target, avail_candidates)]

        if len(avail_candidates) <= 8:
            best_S, best_score = (), float('inf')
            for r in range(len(avail_candidates) + 1):
                for combo in itertools.combinations(avail_candidates, r):
                    sc = calc_ebic(target, list(combo))
                    if sc < best_score:
                        best_score, best_S = sc, combo
            res = (tuple(sorted(best_S)), best_score)
            parent_cache[(target, avail_candidates)] = res
            return res
        else:
            current_S = []
            current_score = calc_ebic(target, current_S)
            changed = True
            while changed:
                changed = False
                best_fwd_item, best_fwd_score = None, current_score
                for c in avail_candidates:
                    if c not in current_S:
                        sc = calc_ebic(target, current_S + [c])
                        if sc < best_fwd_score:
                            best_fwd_score, best_fwd_item = sc, c
                if best_fwd_item is not None:
                    current_S.append(best_fwd_item)
                    current_score = best_fwd_score
                    changed = True
                if len(current_S) > 1:
                    best_bwd_item, best_bwd_score = None, current_score
                    for c in current_S:
                        test_S = [x for x in current_S if x != c]
                        sc = calc_ebic(target, test_S)
                        if sc < best_bwd_score:
                            best_bwd_score, best_bwd_item = sc, c
                    if best_bwd_item is not None:
                        current_S.remove(best_bwd_item)
                        current_score = best_bwd_score
                        changed = True
            res = (tuple(sorted(current_S)), current_score)
            parent_cache[(target, avail_candidates)] = res
            return res

    def score_order(order):
        total_score = 0
        dag = {}
        for pos, i in enumerate(order):
            pred = order[:pos]
            avail = tuple(sorted([x for x in pred if x in cand[i]]))
            best_S, sc = get_best_parents(i, avail)
            total_score += sc
            dag[i] = best_S
        return total_score, dag

    def hc(order):
        best_order = list(order)
        best_score, best_dag = score_order(best_order)
        while True:
            improved = False
            for i in range(d):
                node = best_order[i]
                for j in range(d):
                    if i == j: continue
                    new_order = best_order[:i] + best_order[i+1:]
                    new_order.insert(j, node)
                    sc, dag = score_order(new_order)
                    if sc < best_score:
                        best_score, best_order, best_dag = sc, new_order, dag
                        improved = True
            if not improved:
                break
        return best_order, best_score, best_dag

    variances = np.diag(C)
    restarts = [list(np.argsort(variances)), list(np.argsort(-variances))]
    for _ in range(8):
        rand_o = list(range(d))
        np.random.shuffle(rand_o)
        restarts.append(rand_o)

    global_best_score = float('inf')
    global_best_dag = None
    for init_order in restarts:
        _, sc, dag = hc(init_order)
        if sc < global_best_score:
            global_best_score, global_best_dag = sc, dag

    dag_graph = GeneralGraph(nodes)
    for i in range(d):
        for p in global_best_dag[i]:
            edge = Edge(nodes[p], nodes[i], Endpoint.TAIL, Endpoint.ARROW)
            dag_graph.add_edge(edge)

    try:
        cpdag = dag2cpdag(dag_graph)
    except:
        cpdag = dag_graph
    return cpdag

